   431→/**
   432→ * @summary List all sources
   433→ */
   434→
   435→export function useListSources<
   436→  TData = Awaited<ReturnType<typeof listSources>>,
   437→  TError = ErrorType<unknown>,
   438→>(options?: {
   439→  query?: UseQueryOptions<
   440→    Awaited<ReturnType<typeof listSources>>,
   441→    TError,
   442→    TData
   443→  >;
   444→  request?: SecondParameter<typeof customFetch>;
   445→}): UseQueryResult<TData, TError> & { queryKey: QueryKey } {
   446→  const queryOptions = getListSourcesQueryOptions(options);
   447→
   448→  const query = useQuery(queryOptions) as UseQueryResult<TData, TError> & {
   449→    queryKey: QueryKey;
   450→  };
   451→
   452→  return { ...query, queryKey: queryOptions.queryKey };
   453→}
