   455→/**
   456→ * @summary Create source
   457→ */
   458→export const getCreateSourceUrl = () => {
   459→  return `/api/sources`;
   460→};
   461→
   462→export const createSource = async (
   463→  createSourceRequest: CreateSourceRequest,
   464→  options?: RequestInit,
   465→): Promise<SourceWithUrls> => {
   466→  return customFetch<SourceWithUrls>(getCreateSourceUrl(), {
